UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('0488e52d-029e-4608-9167-dc1b2d481a01'::uuid, 'Le ralentissement métabolique favorise le surpoids, l''extrait de thé vert aide à stimuler la thermogenèse et la dépense énergétique.'),('04297e26-7f36-4999-b2eb-43b7d61cf881'::uuid, 'Le syndrome du côlon irritable est lié à un déséquilibre de la flore, ces probiotiques spécifiques aident à restaurer la perméabilité intestinale.'),('95f5a646-8fa1-43eb-b831-57eca1fcf11f'::uuid, 'Le SII implique une flore intestinale perturbée, ces souches probiotiques aident à rééquilibrer le microbiote et la fonction digestive.'),('01d01ba3-cfc1-4c01-ab2a-6d130c39129c'::uuid, 'Les antibiotiques peuvent déséquilibrer la flore intestinale, ces probiotiques aident à restaurer l''équilibre microbien et soutenir l''immunité.'),('9c7a32b2-8b7d-4501-858d-8f366336490b'::uuid, 'Les antibiotiques peuvent déséquilibrer la flore intestinale, ces probiotiques aident à restaurer l''équilibre microbien et soutenir l''immunité.'),('37ed6285-fa2d-4c14-8d92-a59fc0db6d75'::uuid, 'Les antibiotiques peuvent déséquilibrer la flore intestinale, ces probiotiques aident à restaurer l''équilibre microbien et soutenir l''immunité.'),('b24c15b1-b22c-4b94-b2c0-59aa0994cc9e'::uuid, 'Le syndrome métabolique perturbe la gestion du sucre, le chrome aide à réguler la glycémie et améliorer la sensibilité à l''insuline.'),('5933a137-e41e-4ba1-aea0-06e8a32bc3da'::uuid, 'Le syndrome métabolique peut entraîner une prise de poids, le konjac aide à réduire l''absorption de graisses et sucres.'),('e9509129-f843-4269-9627-54ce37016702'::uuid, 'Le syndrome métabolique est souvent associé à des triglycérides élevés, les Oméga-3 aident à améliorer le profil lipidique sanguin.'),('165e4394-1ca3-4c23-9437-eea06c51c0df'::uuid, 'Le SPM peut provoquer une excitabilité nerveuse et musculaire, le magnésium et la vitamine B6 aident à la relaxation et réduisent la fatigue.'),('b09c3cad-2952-4269-a5fa-189564ab4444'::uuid, 'Les déséquilibres hormonaux prémenstruels peuvent causer de l''inflammation, l''huile d''onagre aide à atténuer les symptômes liés.'),('a8fac272-e6c0-4359-b9d6-d4ab53265311'::uuid, 'Le SPM peut provoquer une excitabilité nerveuse, le magnésium et la vitamine B6 aident à la relaxation musculaire et réduisent l''irritabilité.'),('0ab356c1-7125-40ff-800b-0c32dabb72fd'::uuid, 'La tachycardie peut survenir lors de carences nutritionnelles, des multivitamines aident à optimiser le fonctionnement cardiovasculaire.'),('0dfbd936-8d0b-40a3-93cb-8534de22b231'::uuid, 'Un déficit en magnésium peut perturber l''activité cardiaque, ce supplément aide à stabiliser le rythme et réduire l''excitabilité.'),('ddc66640-8cfe-4e23-9821-d14eac1880df'::uuid, 'Le microbiote intestinal influence le système nerveux, des probiotiques peuvent soutenir l''équilibre nerveux et cardiovasculaire.'),('ad588afa-0a16-4c63-8a49-692153e3dda2'::uuid, 'Le TDAH est lié à des déséquilibres neurochimiques, des multivitamines aident à soutenir le fonctionnement cérébral et la concentration.'),('f9f3d750-851f-47a8-b364-3df6d4114013'::uuid, 'Le TDAH peut être associé à un déficit en magnésium, ce supplément aide à réguler l''humeur et améliorer la concentration.'),('993f7a47-865b-4552-b977-491cd0073709'::uuid, 'L''axe intestin-cerveau est impliqué dans le TDAH, les probiotiques peuvent moduler l''humeur et la fonction cognitive.'),('ed79b8b3-0eaf-4946-8eb6-4d6a04512737'::uuid, 'La tendinite implique une inflammation locale des tendons, ce gel pénètre la peau pour réduire l''inflammation et la douleur.'),('f6eb16a9-7081-4c07-8fb7-d2aae57d2dbf'::uuid, 'La tendinite nécessite du repos et un soutien articulaire, cette bande aide à immobiliser et stabiliser le tendon pour favoriser la guérison.'),('c1f9e71b-3d85-4e4f-8b5f-2f680e95416f'::uuid, 'La tendinite provoque douleur et inflammation aiguë, la cryothérapie aide à réduire l''inflammation locale et engourdir la zone douloureuse.'),('7cf24d1e-3767-4aa9-bf55-7638429ea832'::uuid, 'La thrombose veineuse altère le retour veineux, les bas de contention exercent une pression graduée pour améliorer la circulation et prévenir la stase.'),('b9db1889-0ea1-471e-a85a-f1b06e1f4e70'::uuid, 'Les oméga-3 aident à réduire l''inflammation systémique et améliorer la fluidité sanguine, diminuant ainsi le risque de thrombose.'),('5491a960-0a6a-4a53-aef9-edcf775bc217'::uuid, 'Les thrombus sont liés au stress oxydatif, la coenzyme Q10 est un antioxydant qui protège les cellules vasculaires.'),('231ca849-9efc-4c67-87dc-e67b05c9c226'::uuid, 'Les TOC peuvent être liés à des déséquilibres neurologiques, des multivitamines aident à soutenir le fonctionnement cérébral et la stabilité émotionnelle.'),('efbc833c-b172-4735-8e41-ad14a24059dc'::uuid, 'Le stress et l''anxiété liés aux TOC peuvent consommer du magnésium, ce supplément aide à calmer le système nerveux.'),('bd1729d0-9a35-4a75-ac23-a78765130ca1'::uuid, 'L''axe intestin-cerveau joue un rôle dans les troubles de l''humeur, des probiotiques peuvent moduler les neurotransmetteurs et réduire l''anxiété.'),('79cfd2b8-5b0e-432b-9e9c-98a59766cd47'::uuid, 'Le torticolis est dû à une contraction musculaire douloureuse, ce patch diffuse de la chaleur pour détendre les muscles et soulager la douleur.'),('e8056557-0686-42d5-a071-24cdbccb7f38'::uuid, 'Le torticolis est une contracture musculaire, ce gel appliqué localement pénètre pour détendre les fibres musculaires et diminuer la douleur.'),('86759f30-7de4-4219-a311-874c7f51bf1e'::uuid, 'Une mauvaise posture nocturne aggrave le torticolis, cet oreiller soutient l''alignement cervical pour réduire la tension musculaire.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;